            Long deductResult = redisTemplate.opsForValue().decrement(stockKey, buyCount);
            // 注：decrement方法对应Redis DECRBY命令，key不存在时返回值为 -buyCount
            if (deductResult < 0) {
                redisTemplate.opsForValue().increment(stockKey, buyCount);
